\label{lemmalagrangianR3}
Let $\tau,\tau'\in[1,\infty)$ and~$\vec x,\vec{x}'\in S^2$. We denote the angle between~$\vec{x}$
and~$\vec{x}'$ by~$\vartheta \in [0, \pi]$ (i.e.\ $\cos \vartheta = \vec{x}\cdot \vec{y}$).
Then the operator product $F_\tau(\vec x)F_{\tau'}(\vec x')$ has the eigenvalues
\begin{equation}\label{evals_product}
\lambda_{1,2}=\frac{1}{4}\: \Big(1+\tau\tau'\cos\vartheta \pm\sqrt{  (1+\tau \tau'\cos \vartheta)^2-(\tau^2-1)(\tau'^2-1)  }\Big) \:.
\end{equation}
Moreover,
\begin{equation}\label{lagrangian_R3}
{\mathcal{L}} \big((\tau, \vec x), (\tau', \vec x') \big) = \frac1{8} \Big( \big( 1+\tau\tau'\cos\vartheta \big)^2-(\tau^2-1)(\tau'^2-1) \Big) \,\big( 1- \chi_{[\vartheta_-,\vartheta_+]}(\vartheta) \big) \:,
\end{equation}
where $ \chi_{[\vartheta_-,\vartheta_+]}$ is the characteristic function of the interval defined by
\begin{equation}\label{eq:critical_angles}
\cos\vartheta_\pm=\frac{-1\mp\sqrt{(\tau^2-1)(\tau'^2-1)}}{\tau\tau'} \:.
\end{equation}

